import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourForm = ({ editingTour, onSuccess, onClose }) => {
  const { user } = useAuth();
  const [formData, setFormData] = useState({ 
    title: '', location: '', startDate: '', endDate: '', 
    description: '', importantNotes: '', capacity: '', 
    price: '', discount: '', status: 'Available'
  });
  const [imagePreview, setImagePreview] = useState(null);

  useEffect(() => {
    if (editingTour) {
      setFormData({ ...editingTour });
      if (editingTour.imageUrl) setImagePreview(editingTour.imageUrl);
    }
  }, [editingTour]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // 排除系統欄位，避免後端報錯
      const { _id, __v, createdAt, updatedAt, imageUrl, ...payload } = formData;

      const config = { headers: { Authorization: `Bearer ${user.token}` } };

      if (editingTour) {
        await axiosInstance.put(`/api/tours/${editingTour._id}`, payload, config);
      } else {
        await axiosInstance.post('/api/tours', payload, config);
      }
      alert('Success!');
      onSuccess();
    } catch (error) {
      alert('Save failed: ' + (error.response?.data?.message || error.message));
    }
  };

  const handleDelete = async () => {
    if (!window.confirm("Are you sure you want to delete this tour?")) return;
    try {
      await axiosInstance.delete(`/api/tours/${editingTour._id}`, {
        headers: { Authorization: `Bearer ${user.token}` }
      });
      alert('Deleted!');
      onSuccess();
    } catch (error) {
      alert('Delete failed');
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-white">
      <div className="flex items-center p-4 border-b sticky top-0 bg-white z-10">
        <button onClick={onClose} className="text-2xl px-2">←</button>
        <h1 className="flex-1 text-center font-bold text-lg">{editingTour ? 'Edit Details' : 'Add Tour'}</h1>
        <button onClick={onClose} className="text-xl px-2">🏠</button>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto flex-1">
        <div>
          <label className="block font-bold mb-1 text-gray-700">Tour Title</label>
          <input type="text" value={formData.title} onChange={(e) => setFormData({ ...formData, title: e.target.value })} className="w-full p-3 border rounded-xl bg-gray-50" required />
        </div>

        <div>
          <label className="block font-bold mb-1 text-gray-700">Location</label>
          <input type="text" value={formData.location} onChange={(e) => setFormData({ ...formData, location: e.target.value })} className="w-full p-3 border rounded-xl bg-gray-50" />
        </div>

        <div className="flex space-x-3">
          <div className="flex-1">
            <label className="block font-bold mb-1 text-gray-700 text-xs">Price (AUD)</label>
            <input type="number" value={formData.price} onChange={(e) => setFormData({ ...formData, price: e.target.value })} className="w-full p-3 border rounded-xl bg-gray-50" required />
          </div>
          <div className="flex-1">
            <label className="block font-bold mb-1 text-gray-700 text-xs">Status</label>
            <select value={formData.status} onChange={(e) => setFormData({ ...formData, status: e.target.value })} className="w-full p-3 border rounded-xl bg-gray-50">
              <option value="Available">Available</option>
              <option value="Unavailable">Sold Out</option>
            </select>
          </div>
        </div>

        <div>
          <label className="block font-bold mb-1 text-gray-700">Description</label>
          <textarea rows="3" value={formData.description} onChange={(e) => setFormData({ ...formData, description: e.target.value })} className="w-full p-3 border rounded-xl bg-gray-50" />
        </div>

        <button type="submit" className="w-full bg-emerald-500 text-white font-bold py-4 rounded-2xl shadow-lg hover:bg-emerald-600 transition-all mt-4">
          {editingTour ? 'Update Changes' : 'Submit'}
        </button>

        {editingTour && (
          <button type="button" onClick={handleDelete} className="w-full text-red-500 font-bold py-2 mt-2 hover:underline">
            Delete Tour Package
          </button>
        )}
      </form>
    </div>
  );
};

export default TourForm;
